// Mapeia módulo para emoji e cor
const moduleMap = {
  'vendas': { emoji: '💰', color: '#1a73e8', label: 'Vendas' },
  'financeiro': { emoji: '💵', color: '#28a745', label: 'Financeiro' },
  'nfe': { emoji: '📄', color: '#fd7e14', label: 'NF-e / Fiscal' },
  'pcp': { emoji: '🏭', color: '#6f42c1', label: 'PCP / Produção' },
  'rh': { emoji: '👥', color: '#e83e8c', label: 'RH' },
  'compras': { emoji: '🛒', color: '#20c997', label: 'Compras' },
  'lgpd': { emoji: '🔒', color: '#6c757d', label: 'LGPD' },
  'logistica': { emoji: '🚚', color: '#17a2b8', label: 'Logística' },
  'dashboard': { emoji: '📊', color: '#343a40', label: 'Dashboard' }
};

const typeMap = {
  'pdf': { icon: '📕', label: 'PDF' },
  'excel': { icon: '📗', label: 'Excel (XLSX)' },
  'csv': { icon: '📋', label: 'CSV' },
  'json': { icon: '📦', label: 'JSON' },
  'xml': { icon: '📜', label: 'XML' },
  'zip': { icon: '📁', label: 'ZIP' }
};

const body = $input.first().json.body || $input.first().json;
const modulo = (body.modulo || 'sistema').toLowerCase();
const tipo = (body.tipo_relatorio || 'pdf').toLowerCase();

const modInfo = moduleMap[modulo] || { emoji: '📊', color: '#333', label: modulo };
const tipInfo = typeMap[tipo] || { icon: '📄', label: tipo.toUpperCase() };

const now = new Date();
const dataFormatada = now.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const horaFormatada = now.toLocaleTimeString('pt-BR', { timeZone: 'America/Sao_Paulo' });

return [{
  json: {
    ...body,
    modulo,
    tipo_relatorio: tipo,
    mod_emoji: modInfo.emoji,
    mod_color: modInfo.color,
    mod_label: modInfo.label,
    tip_icon: tipInfo.icon,
    tip_label: tipInfo.label,
    data_formatada: dataFormatada,
    hora_formatada: horaFormatada,
    nome_relatorio: body.nome_relatorio || 'Relatório',
    usuario: body.usuario || 'Sistema',
    email_destino: body.email_destino || body.email_usuario || '',
    descricao: body.descricao || '',
    parametros: body.parametros || {},
    link_download: body.link_download || ''
  }
}];
